<template><div class="page"><header class="page-head"><div><h1>Utilisateurs</h1><p>Comptes Plex, roles et autorisations du portail.</p></div><button class="icon-button" :disabled="loading" title="Actualiser" @click="load"><RefreshCw :class="{spin:loading}"/></button></header><p v-if="error" class="notice error-text">{{ error }}</p><section class="panel table-wrap"><table><thead><tr><th>Utilisateur</th><th>Email</th><th>Source</th><th>Role</th><th>Connexion</th><th></th></tr></thead><tbody><tr v-for="user in users" :key="user.id"><td><strong>{{ user.custom_name||user.display_name||user.plex_user_id }}</strong><small>{{ user.plex_user_id }}</small></td><td>{{ user.notification_email||user.plex_email||'-' }}</td><td>{{ user.source||'plex' }}</td><td><span class="badge" :class="user.role==='admin'?'available':'pending'">{{ user.role }}</span></td><td>{{ user.can_login?'Autorisee':'Bloquee' }}</td><td><button class="icon-button" :title="user.enabled?'Desactiver':'Activer'" @click="toggle(user)"><Power /></button></td></tr></tbody></table><p v-if="!loading&&users.length===0" class="empty">Aucun utilisateur.</p></section></div></template>
<script setup>import { onMounted,ref } from "vue";import { Power,RefreshCw } from "@lucide/vue";import { api } from "@/api";const users=ref([]),loading=ref(false),error=ref("");async function load(){loading.value=true;error.value="";try{users.value=await api('/api/users')}catch(e){error.value=e.message}finally{loading.value=false}}async function toggle(user){try{await api(`/api/users/${user.id}/enabled`,{method:'PUT',body:JSON.stringify({enabled:!user.enabled})});await load()}catch(e){error.value=e.message}}onMounted(load);</script>
